import React from 'react';
import { beforeUpdate } from 'svelte';

export default function Games() {
  const games = [
      { title: 'Mystic Quest', img_path: 'imgs/ai.png' },
      { title: 'Mystic Quest', img_path: 'imgs/ai2.png' },
      { title: 'Mystic Quest', img_path: 'imgs/bed.png' },
      { title: 'Mystic Quest', img_path: 'imgs/floor.png' },
      { title: 'Mystic Quest', img_path: 'imgs/klara.png' },
      { title: 'Mystic Quest', img_path: 'imgs/table.png' },
      { title: 'Mystic Quest', img_path: 'imgs/tilt.png' },
      { title: 'Mystic Quest', img_path: 'imgs/toy.png' },
  ];

imgs/ai.png
imgs/ai2.png
imgs/bed.png
imgs/floor.png
imgs/klara.png
imgs/table.png
imgs/tilt.png
imgs/toy.png

  return (
    <main>
      <h1>Browse Our Selection</h1>
      <section>
        {
            games.map(game => (
                        <GameCard title={game.title} genre={game.genre} color={game.color} animal={game.animal} />
                    )
                )
        }
      </section>
    </main>
  );
}

function GameCard({ title='a', img_path='imgs/ai.png' }) {
  return (
    <article className="game-card">
      <h2>{title }</h2>
      <img src={img_path}/>
    </article>
  );
}
